type (
  ArchiveFeatureRequest = models.NamespacedID
  ArchiveFeatureResponse = any
  ArchiveFeatureHandler  httptransport.HandlerWithArgs[ArchiveFeatureRequest, ArchiveFeatureResponse, string]
)
func (h *handler) ArchiveFeature() ArchiveFeatureHandler {
  return httptransport.NewHandlerWithArgs(
    func(ctx context.Context, r *http.Request, id string) (ArchiveFeatureRequest, error) {
      ns, err := h.resolveNamespace(ctx)
      if err != nil { return ArchiveFeatureRequest{}, err }
      return models.NamespacedID{Namespace: ns, ID: id}, nil
    },
    func(ctx context.Context, req ArchiveFeatureRequest) (ArchiveFeatureResponse, error) {
      return nil, h.connector.ArchiveFeature(ctx, req)
    },
    commonhttp.EmptyResponseEncoder[ArchiveFeatureResponse](http.StatusNoContent),
    httptransport.AppendOptions(h.options, httptransport.WithOperationName("archive-feature"), httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()), httptransport.WithErrorEncoder(errorEncoder()))...,
  )
}
